const DEFAULT_CONFIG = {
  feeTolerance: 0.035,
  amountTenPercentTolerance: 0.10,
  nameFuzzyThreshold: 0.85,
  autoMatchThreshold: 85,
  reviewThreshold: 60,
  timestamp24hMs: 24 * 60 * 60 * 1000,
  timestamp48hMs: 48 * 60 * 60 * 1000,
  scoreEmailExact: 50,
  scoreNameFuzzy: 20,
  scoreAmountExact: 40,
  scoreAmountFeeTolerance: 25,
  scoreAmountTenPercent: 10,
  scoreTimestamp24h: 10,
  scoreTimestamp48h: 5,
};

function levenshtein(a, b) {
  const rows = a.length + 1;
  const cols = b.length + 1;
  const d = Array.from({ length: rows }, (_, i) => [i, ...Array(cols - 1).fill(0)]);
  for (let j = 0; j < cols; j++) d[0][j] = j;
  for (let i = 1; i < rows; i++) {
    for (let j = 1; j < cols; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      d[i][j] = Math.min(d[i - 1][j] + 1, d[i][j - 1] + 1, d[i - 1][j - 1] + cost);
    }
  }
  return d[rows - 1][cols - 1];
}

function nameSimilarity(nameA, nameB) {
  const a = nameA.trim().toLowerCase();
  const b = nameB.trim().toLowerCase();
  const maxLen = Math.max(a.length, b.length);
  if (maxLen === 0) return 0;
  return 1 - levenshtein(a, b) / maxLen;
}

function scorePair(payment, deal, config) {
  if (payment.currency !== deal.currency) return null;

  const reasons = [];
  let score = 0;
  let isCandidate = false;

  if (payment.email && deal.email && payment.email === deal.email) {
    isCandidate = true;
    score += config.scoreEmailExact;
    reasons.push('email_exact');
  } else if (!payment.email && !deal.email && payment.name && deal.name) {
    if (nameSimilarity(payment.name, deal.name) > config.nameFuzzyThreshold) {
      isCandidate = true;
      score += config.scoreNameFuzzy;
      reasons.push('name_fuzzy');
    }
  }

  if (!isCandidate) return null;

  if (payment.amount != null && deal.amount != null) {
    const paymentCents = Math.round(payment.amount * 100);
    const dealCents = Math.round(deal.amount * 100);
    const diffRatio = dealCents === 0 ? 0 : Math.abs(paymentCents - dealCents) / dealCents;
    if (paymentCents === dealCents) {
      score += config.scoreAmountExact;
      reasons.push('amount_exact');
    } else if (diffRatio <= config.feeTolerance) {
      score += config.scoreAmountFeeTolerance;
      reasons.push('amount_fee_adjusted');
    } else if (diffRatio <= config.amountTenPercentTolerance) {
      score += config.scoreAmountTenPercent;
      reasons.push('amount_within_10pct');
    } else {
      reasons.push('amount_mismatch');
    }
  }

  if (payment.timestamp && deal.timestamp) {
    const diffMs = Math.abs(new Date(payment.timestamp).getTime() - new Date(deal.timestamp).getTime());
    if (diffMs <= config.timestamp24hMs) {
      score += config.scoreTimestamp24h;
      reasons.push('timestamp_within_24h');
    } else if (diffMs <= config.timestamp48hMs) {
      score += config.scoreTimestamp48h;
      reasons.push('timestamp_within_48h');
    }
  }

  return { score, reasons };
}

function match(payments, deals, config) {
  const cfg = { ...DEFAULT_CONFIG, ...config };

  const pairs = [];
  for (const payment of payments) {
    for (const deal of deals) {
      const scored = scorePair(payment, deal, cfg);
      if (scored && scored.score >= cfg.reviewThreshold) {
        pairs.push({ payment, deal, confidence: scored.score, reasons: scored.reasons });
      }
    }
  }
  pairs.sort((a, b) => b.confidence - a.confidence);

  const claimedPayments = new Set();
  const claimedDeals = new Set();
  const matched = [];
  const review = [];

  for (const pair of pairs) {
    if (claimedPayments.has(pair.payment) || claimedDeals.has(pair.deal)) continue;
    claimedPayments.add(pair.payment);
    claimedDeals.add(pair.deal);
    if (pair.confidence >= cfg.autoMatchThreshold) {
      matched.push(pair);
    } else {
      review.push(pair);
    }
  }

  const unmatchedPayments = payments.filter((p) => !claimedPayments.has(p));
  const unmatchedDeals = deals.filter((d) => !claimedDeals.has(d));

  return { matched, review, unmatchedPayments, unmatchedDeals };
}

// Driver for the "Match" Code node. Appended after src/matcher.js.
const { payments, deals } = $input.first().json;
return [{ json: { matchResult: match(payments, deals, {}) } }];

const DEFAULT_CONFIG = {
  duplicateWindowMs: 60 * 60 * 1000,
  excludeSubscriptions: true,
};

function isDuplicateOf(a, b, windowMs) {
  if (a === b) return false;
  if (!a.email || a.email !== b.email) return false;
  const aCents = Math.round(a.amount * 100);
  const bCents = Math.round(b.amount * 100);
  if (aCents !== bCents) return false;
  const diffMs = Math.abs(new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
  return diffMs <= windowMs;
}

function classify(matchResult, config) {
  const cfg = { ...DEFAULT_CONFIG, ...config };
  const exceptions = [];

  for (const pair of [...matchResult.matched, ...matchResult.review]) {
    const { payment, deal, confidence, reasons } = pair;
    if (payment.refunded && deal.stage === 'closedwon') {
      exceptions.push({ type: 'ORPHAN_REFUND', payment, deal, confidence });
    } else if (reasons.includes('amount_within_10pct') || reasons.includes('amount_mismatch')) {
      exceptions.push({ type: 'AMOUNT_MISMATCH', payment, deal, confidence });
    } else if (matchResult.review.includes(pair)) {
      exceptions.push({ type: 'REVIEW', payment, deal, confidence });
    }
  }

  for (const deal of matchResult.unmatchedDeals) {
    if (deal.stage === 'closedwon' && deal.email) {
      exceptions.push({ type: 'DEAL_NO_PAYMENT', deal });
    }
  }

  const allPayments = [
    ...matchResult.matched.map((m) => m.payment),
    ...matchResult.review.map((r) => r.payment),
    ...matchResult.unmatchedPayments,
  ];

  for (const payment of matchResult.unmatchedPayments) {
    const duplicateOf = allPayments.find((other) => isDuplicateOf(payment, other, cfg.duplicateWindowMs));
    if (duplicateOf) {
      exceptions.push({ type: 'DUPLICATE_CHARGE', payment, duplicateOf });
    } else if (cfg.excludeSubscriptions && payment.subscriptionId != null) {
      // subscription renewal, no new deal expected — not an exception (PLAN.md §7.4)
    } else {
      exceptions.push({ type: 'PAYMENT_NO_DEAL', payment, unmatchable: !payment.email });
    }
  }

  return exceptions;
}

// Driver for the "Classify" Code node. Appended after src/classify.js.
// Output feeds two branches: Split Out(exceptions) -> Postgres, and
// Format -> Slack/Sheets. Both need matchResult kept alongside exceptions.
const { matchResult } = $input.first().json;
const exceptions = classify(matchResult, {});
return [{ json: { matchResult, exceptions } }];

const DEFAULT_CONFIG = {
  maxExceptionsInMessage: 10,
};

// DUPLICATE_CHARGE and PAYMENT_NO_DEAL first (money is wrong right now),
// REVIEW last. Middle order is our own call: ORPHAN_REFUND (money already
// moved backwards) before AMOUNT_MISMATCH before DEAL_NO_PAYMENT (deal is
// stuck, not urgent-money-wrong). Per PLAN.md section "Phase 4".
const SEVERITY_ORDER = [
  'DUPLICATE_CHARGE',
  'PAYMENT_NO_DEAL',
  'ORPHAN_REFUND',
  'AMOUNT_MISMATCH',
  'DEAL_NO_PAYMENT',
  'REVIEW',
];

function exceptionAmount(exception) {
  if (exception.payment) return exception.payment.amount;
  if (exception.deal) return exception.deal.amount;
  return 0;
}

function exceptionCustomer(exception) {
  return (exception.payment && exception.payment.name) || (exception.deal && exception.deal.name) || null;
}

function exceptionEmail(exception) {
  return (exception.payment && exception.payment.email) || (exception.deal && exception.deal.email) || null;
}

// Sheet formula injection: Excel/Google Sheets runs a cell starting with
// =/+/-/@ as a formula. Customer name/email are attacker-influenceable
// (whatever the customer typed at checkout), so neutralize before they
// reach a spreadsheet cell.
function sanitizeForSheet(value) {
  if (value == null) return value;
  return /^[=+\-@]/.test(value) ? `'${value}` : value;
}

// Slack mrkdwn injection: &, <, > have special meaning in Slack's mrkdwn
// (link/entity syntax) and must be escaped before interpolation into block
// text, per Slack's own escaping rules.
function escapeMrkdwn(value) {
  return String(value).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function exceptionLine(exception) {
  const customer = escapeMrkdwn(exceptionCustomer(exception) || 'unknown');
  const amount = exceptionAmount(exception);
  const amountStr = amount != null ? `$${amount.toFixed(2)}` : 'unknown amount';
  return `*${exception.type}* — ${customer} — ${amountStr}`;
}

function summarize(matchResult, exceptions) {
  const totalPayments =
    matchResult.matched.length + matchResult.review.length + matchResult.unmatchedPayments.length;
  const exceptionCount = exceptions.length;
  const cleanCount = totalPayments - exceptionCount;
  const unreconciledAmount = exceptions.reduce((sum, e) => sum + (exceptionAmount(e) || 0), 0);

  return { totalPayments, cleanCount, exceptionCount, unreconciledAmount };
}

function formatSlackMessage(matchResult, exceptions, config) {
  const cfg = { ...DEFAULT_CONFIG, ...config };
  const summary = summarize(matchResult, exceptions);

  const headline = `${summary.totalPayments} payments · ${summary.cleanCount} clean · ${summary.exceptionCount} exceptions · $${summary.unreconciledAmount.toFixed(2)} unreconciled`;

  const ordered = [...exceptions].sort(
    (a, b) => SEVERITY_ORDER.indexOf(a.type) - SEVERITY_ORDER.indexOf(b.type)
  );
  const shown = ordered.slice(0, cfg.maxExceptionsInMessage);
  const remaining = ordered.length - shown.length;

  const lines = shown.map(exceptionLine);
  if (remaining > 0) lines.push(`…and ${remaining} more, see sheet.`);

  return {
    blocks: [
      { type: 'section', text: { type: 'mrkdwn', text: `*${headline}*` } },
      ...lines.map((line) => ({ type: 'section', text: { type: 'mrkdwn', text: line } })),
    ],
  };
}

function formatSheetRows(exceptions) {
  return exceptions.map((exception) => {
    const record = exception.payment || exception.deal;
    return {
      date: record.timestamp,
      type: exception.type,
      amount: exceptionAmount(exception),
      customer: sanitizeForSheet(exceptionCustomer(exception)),
      email: sanitizeForSheet(exceptionEmail(exception)),
      confidence: exception.confidence != null ? exception.confidence : null,
      paymentLink: exception.payment ? exception.payment.url : null,
      dealLink: exception.deal ? exception.deal.url : null,
      resolved: false, // report-only: this bot never reads the checkbox back, decision logged in progress.md
    };
  });
}

// Driver for the "Format" Code node. Appended after src/format.js.
// Produces both outputs format.js owns: Slack blocks and Sheet rows.
// Split Out(sheetRows) downstream feeds the Sheets append node; `blocks`
// goes straight to the Slack HTTP Request node.
const { matchResult, exceptions } = $input.first().json;
const slack = formatSlackMessage(matchResult, exceptions, {});
const sheetRows = formatSheetRows(exceptions);
return [{ json: { blocks: slack.blocks, sheetRows } }];

function normalizeEmail(raw) {
  if (raw == null) return null;
  const trimmed = String(raw).trim().toLowerCase();
  const atIndex = trimmed.indexOf('@');
  if (atIndex === -1) return trimmed;
  const local = trimmed.slice(0, atIndex);
  const domain = trimmed.slice(atIndex);
  const plusIndex = local.indexOf('+');
  const cleanLocal = plusIndex === -1 ? local : local.slice(0, plusIndex);
  return cleanLocal + domain;
}

function normalizeAmount(raw, source) {
  if (raw == null) return null;
  const dollars = source === 'stripe' ? Number(raw) / 100 : Number(raw);
  return Math.round(dollars * 100) / 100;
}

function normalizeTimestamp(raw, source) {
  if (raw == null) return null;
  const ms = source === 'stripe' ? Number(raw) * 1000 : Number(raw);
  return new Date(ms).toISOString();
}

// Driver for the "Normalize" Code node. Appended after src/normalize.js's
// (export-stripped) functions by inject.js. Reads raw Stripe/HubSpot shapes
// straight off named upstream nodes -- not off Merge1's combined input --
// so it doesn't depend on Merge1's combine mode being correct.
//
// Stripe charge object: https://docs.stripe.com/api/charges/object
// HubSpot deal/contact: legacy v1 shape, properties nested as {value, ...}
// (confirmed against this workflow's Filter1 condition and live execution
// data -- see the Split Out screenshot from this session).

const rawCharges = $('Filter').all().map((i) => i.json);
const rawDeals = $('Filter1').all().map((i) => i.json);
const rawContacts = $('Get a contact').all().map((i) => i.json);

// PLAN.md §7.2: zero-amount charges are Stripe card-validation artifacts,
// ignore entirely. §7.4: declined charges never moved money, ignore too.
const payments = rawCharges
  .filter((c) => c.status === 'succeeded' && c.amount > 0)
  .map((c) => ({
    source: 'stripe',
    id: c.id,
    email: normalizeEmail(c.billing_details?.email || c.receipt_email || null),
    name: c.billing_details?.name || null,
    amount: normalizeAmount(c.amount, 'stripe'),
    currency: c.currency,
    timestamp: normalizeTimestamp(c.created, 'stripe'),
    refunded: Boolean(c.refunded),
    refundedAmount: normalizeAmount(c.amount_refunded || 0, 'stripe'),
    // Charge object has no subscription field without expanding `invoice`,
    // which "Get many charges" doesn't do yet -- Ahad's fetch-node follow-up
    // (see progress.md "Next session"). Always null until that lands.
    subscriptionId: null,
    url: `https://dashboard.stripe.com/test/payments/${c.id}`,
  }));

const deals = rawDeals.map((d, i) => {
  const contact = rawContacts[i] || {};
  const props = d.properties || {};
  const cprops = contact.properties || {};
  const firstname = cprops.firstname?.value || '';
  const lastname = cprops.lastname?.value || '';
  const name = firstname || lastname ? `${firstname} ${lastname}`.trim() : null;

  return {
    source: 'hubspot',
    id: String(d.dealId),
    email: normalizeEmail(cprops.email?.value || null),
    name,
    amount: normalizeAmount(props.amount?.value ?? null, 'hubspot'),
    currency: 'usd',
    timestamp: normalizeTimestamp(props.closedate?.value ?? null, 'hubspot'),
    stage: props.dealstage?.value || null,
    url: `https://app.hubspot.com/contacts/${d.portalId}/deal/${d.dealId}`,
  };
});

return [{ json: { payments, deals } }];

const runId = $input.first().json.id;
const { exceptions, matchResult } = $('Classify').first().json;
return [{ json: { runId, exceptions, matchResult } }];
